import{N as e,h as t,k as n,p as r,u as i}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as a}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const o=JSON.parse(`{"title":"Mappings migrieren","description":"Lerne, wie du die verschleierten Mappings deines Mods migrierst.","frontmatter":{"title":"Mappings migrieren","description":"Lerne, wie du die verschleierten Mappings deines Mods migrierst.","authors":["ArduFish","asiekierka","cassiancc","Daomephsta","deirn","Earthcomputer","florensie","Friendly-Banana","IMB11","jamierocks","JamiesWhiteShirt","liach","MildestToucan","modmuss50","modmuss50","Spinoscythe","UpcraftLP"],"authors-nogithub":["basil4088"],"files":[]},"headers":[],"relativePath":"de_de/develop/migrating-mappings/index.md","filePath":"translated/de_de/develop/migrating-mappings/index.md","lastUpdated":1770561656000}`);var s={name:`de_de/develop/migrating-mappings/index.md`};function c(a,o,s,c,l,u){let d=e(`ChoiceComponent`);return n(),i(`div`,null,[o[0]||=r(`<h1 id="h1" tabindex="-1">Mappings migrieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Mappings migrieren”">​</a></h1><p>Möglicherweise möchtest du von Yarn zu Mojang Mappings migrieren, insbesondere wenn du planst, <a href="#whats-going-on-with-mappings">deinen Mod nach dem Erscheinen des Gamedrop Mounts of Mayhem</a> zu aktualisieren, oder anders herum.</p><p>Es gibt zwei Möglichkeiten, dies zu erreichen: Du kannst entweder das <strong>Loom Gradle Plugin</strong> oder das <strong>Ravel IntelliJ IDEA Plugin</strong> verwenden.</p><p>Loom bietet eine halbautomatische Migration der Mappings über die Aufgabe <code>migrateMappings</code>, <strong>unterstützt jedoch keine Migration von in Kotlin geschriebenem Code</strong>.</p><p>Ravel ist ein Plugin für IntelliJ IDEA, das einen GUI-Dialog für die Migration hinzufügt. Im Gegensatz zu Loom unterstützt Ravel jedoch auch <strong>Kotlin</strong>. Darüber hinaus könnte Ravel bei komplexeren Projekten eine bessere Leistung als Loom erzielen, da es IDE zur Lösung von Änderungen verwendet.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Die Fabric-API verwendete Ravel, um von Yarn zu Mojang Mappings zu migrieren. Siehe <a href="https://github.com/FabricMC/fabric/pull/4960" target="_blank" rel="noreferrer">PR #4690 im Fabric API Repository</a>.</p></div><p>Keine der beiden Optionen ist perfekt, und du musst die Ergebnisse weiterhin überprüfen und manuelle Korrekturen vornehmen, insbesondere bei der Migration von Mixins.</p>`,7),t(d,{choices:[{name:`Loom Gradle Plugin`,href:`./loom`,icon:`simple-icons:gradle`,color:`#4DC9C0`},{name:`Ravel IntelliJ IDEA Plugin`,href:`./ravel`,icon:`simple-icons:intellijidea`,color:`#FE2857`}]}),o[1]||=r(`<h2 id="whats-going-on-with-mappings" tabindex="-1">Was ist mit den Mappings los? <a class="header-anchor" href="#whats-going-on-with-mappings" aria-label="Permalink to “Was ist mit den Mappings los?”">​</a></h2><p>In der Vergangenheit hat die Minecraft: Java Edition Verschleierung eingesetzt, was zur Entwicklung von Verschleierungskarten geführt hat, die Fabric Loom für Modding verwendet. Es gab zwei Möglichkeiten: entweder die Fabric-eigenen Yarn-Mappings oder die offiziellen Mojang-Mappings.</p><p>Mojang hat kürzlich angekündigt, dass <a href="https://www.minecraft.net/en-us/article/removing-obfuscation-in-java-edition" target="_blank" rel="noreferrer">sie die Code-Verschleierung aus der Minecraft: Java Edition</a> entfernen, woraufhin das Fabric-Projekt <a href="https://fabricmc.net/2025/10/31/obfuscation.html" target="_blank" rel="noreferrer">mit seinen Plan zur Umsetzung dieser Änderung</a> gefolgt ist. Wenn du vorhast, deinen Mod auf diese Version zu aktualisieren, musst du vor dem Update zunächst zu Mojangs Verschleierungsmappings wechseln.</p><h2 id="mappings" tabindex="-1">Was sind Mappings? <a class="header-anchor" href="#mappings" aria-label="Permalink to “Was sind Mappings?”">​</a></h2><p>Die Minecraft: Java Edition wurde seit seiner Veröffentlichung verschleiert, was bedeutet, dass seine Codes mit menschenfreundlichen Klassennamen wie <code>Creeper</code> durch unverständliche Zeichenfolgen wie <code>brc</code> ersetzt wurden. Um das Modding zu vereinfachen, verwendet Fabric Loom Verschleierungskarten: Referenzen, die verschleierte Klassennamen wie <code>brc</code> wieder in menschenfreundliche Namen wie <code>CreeperEntity</code> übersetzen.</p><p>Als Fabric-Entwickler wirst du auf drei Hauptgruppen von Namen stoßen:</p><ul><li><strong>Intermediary</strong>: Das von kompilierten Fabric-Mods verwendete Mapping-Set; beispielsweise kann <code>brc</code> zu <code>class_1548</code> werden. Der Sinn hinter Intermediary besteht darin, über verschiedene Versionen hinweg eine stabile Reihe von Namen anzubieten, da sich verschleierte Klassennamen mit jeder neuen Version von Minecraft ändern. Dadurch können Mods, die für eine bestimmte Version entwickelt wurden, oft auch auf anderen Versionen funktionieren, solange die betroffenen Teile des Spiels nicht zu stark verändert wurden.</li><li><strong>Yarn</strong>: Ein von Fabric entwickeltes Open- Source-Mapping-Set, mit dem Menschen Mods schreiben können. Die meisten Fabric-Mods verwendeten Yarn Mappings, da diese vor 2025 der Standard waren. Ein Beispiel für eine Zuordnung könnte <code>CreeperEntity</code> sein.</li><li><strong>Mojang Mappings</strong>: Die offiziellen Verschleierungsmappings des Spiels, die 2019 von Mojang veröffentlicht wurden, um die Mod-Entwicklung zu unterstützen. Insbesondere fehlen in den Verschleierungsmappings von Mojang Parameternamen und Javadocs, weshalb einige Benutzer zusätzlich <a href="https://parchmentmc.org/" target="_blank" rel="noreferrer">Parchment</a> über die offiziellen Mappings legen. Ein Beispiel für ein Mapping könnte <code>Creeper</code> sein.</li></ul><p>Minecraft 26.1 wird nicht verschleiert sein und enthält Parameternamen, sodass keine Mappings erforderlich sind.</p>`,8)])}var l=a(s,[[`render`,c]]);export{o as __pageData,l as default};